$p = "$env:USERPROFILE\Desktop\AssetManagement\AssetManagement.Web\Controllers\AssetController.cs"
$enc = [System.Text.Encoding]::UTF8
$c = [System.IO.File]::ReadAllText($p, $enc)
$old = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
$new = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
if ($c.Contains($old)) {
    $c = $c.Replace($old, $new)
    [System.IO.File]::WriteAllText($p, $c, $enc)
    Write-Host "OK: DeleteAll now reseeds Identity columns" -ForegroundColor Green
} else {
    Write-Host "WARN: pattern not found exactly - showing current DeleteAll:" -ForegroundColor Red
    ($c -split "`n") | Select-String "DeleteAll" -Context 0,30 | Select-Object -First 1
}
cd "$env:USERPROFILE\Desktop\AssetManagement"
dotnet build 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Build OK!" -ForegroundColor Green }